insert into uspt_bsns_pblanc_detail
							(
								pblanc_detail_id
								, pblanc_id
								, sj
								, detail_cn
								, creator_id
								, created_dt
								, updater_id
								, updated_dt
							)
					values	(
								#{pblancDetailId}
								, #{pblancId}
								, #{sj}
								, #{detailCn}
								, #{creatorId}
								, #{createdDt}
								, #{updaterId}
								, #{updatedDt}
							)

mapper.update:
/** UsptBsnsPblancDetailDao.update */
update uspt_bsns_pblanc_detail
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, sj			= #{sj}
	, detail_cn		= #{detailCn}
where
	pblanc_id = #{pblancId}
	and pblanc_detail_id = #{pblancDetailId}

